class Solution:
    def leftmostBuildingQueries(self, heights, queries):
        n = len(heights)
        res = []
        for x, y in queries:
            a, b = (x, y) if x <= y else (y, x)
            if a == b:
                res.append(a)
                continue
            if heights[a] < heights[b]:
                res.append(b)
                continue
            thresh = max(heights[a], heights[b])
            found = -1
            for k in range(b + 1, n):
                if heights[k] > thresh:
                    found = k
                    break
            res.append(found)
        return res

