import heapq
from collections import defaultdict

class Solution:
    def leftmostBuildingQueries(self, heights, queries):
        n = len(heights)
        q = len(queries)
        ans = [-1] * q
        pending_at = defaultdict(list)
        for qi, (x, y) in enumerate(queries):
            a, b = (x, y) if x <= y else (y, x)
            if a == b:
                ans[qi] = a
            elif heights[a] < heights[b]:
                ans[qi] = b
            else:
                pending_at[b].append((max(heights[a], heights[b]), qi))
        heap = []
        for i in range(n):
            while heap and heap[0][0] < heights[i]:
                _, qi = heapq.heappop(heap)
                ans[qi] = i
            for item in pending_at.get(i, []):
                heapq.heappush(heap, item)
        return ans

