var leftmostBuildingQueries = function(heights, queries) {
    const n = heights.length;
    const q = queries.length;
    const ans = new Array(q).fill(-1);
    const pendingAt = new Map();
    for (let qi = 0; qi < q; qi++) {
        const x = queries[qi][0], y = queries[qi][1];
        const a = Math.min(x, y), b = Math.max(x, y);
        if (a === b) {
            ans[qi] = a;
        } else if (heights[a] < heights[b]) {
            ans[qi] = b;
        } else {
            if (!pendingAt.has(b)) pendingAt.set(b, []);
            pendingAt.get(b).push([Math.max(heights[a], heights[b]), qi]);
        }
    }
    const heap = [];
    function push(item) {
        heap.push(item);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p][0] <= heap[i][0]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    }
    function pop() {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                const l = 2 * i + 1, r = 2 * i + 2;
                let smallest = i;
                if (l < heap.length && heap[l][0] < heap[smallest][0]) smallest = l;
                if (r < heap.length && heap[r][0] < heap[smallest][0]) smallest = r;
                if (smallest === i) break;
                [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
                i = smallest;
            }
        }
        return top;
    }
    for (let i = 0; i < n; i++) {
        while (heap.length > 0 && heap[0][0] < heights[i]) {
            const popped = pop();
            ans[popped[1]] = i;
        }
        if (pendingAt.has(i)) {
            for (const item of pendingAt.get(i)) push(item);
        }
    }
    return ans;
};
